package com.parkflow.mall.payment;
import com.parkflow.mall.payment.model.*; import com.parkflow.mall.payment.repository.PaymentOrderRepository; import io.jsonwebtoken.Jwts; import io.jsonwebtoken.security.Keys; import java.nio.charset.StandardCharsets; import java.time.*; import java.util.*; import org.junit.jupiter.api.*; import org.springframework.beans.factory.annotation.*; import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc; import org.springframework.boot.test.context.SpringBootTest; import org.springframework.http.MediaType; import org.springframework.test.web.servlet.MockMvc; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest @AutoConfigureMockMvc class PaymentReconciliationTests { static final String SECRET="parkflow-local-development-secret-change-me-2026"; @Autowired MockMvc mvc; @Autowired PaymentOrderRepository orders;
 @Test void reconciliationRequiresAdminAndAdminCanListRunAndGetUnknown() throws Exception { mvc.perform(post("/api/payments/reconciliation/run").content("{}").contentType(MediaType.APPLICATION_JSON)).andExpect(status().isUnauthorized()); mvc.perform(post("/api/payments/reconciliation/run").header("Authorization","Bearer bad").content("{}").contentType(MediaType.APPLICATION_JSON)).andExpect(status().isUnauthorized()); mvc.perform(post("/api/payments/reconciliation/run").header("Authorization","Bearer "+jwt("PARKING_STAFF")).content("{}").contentType(MediaType.APPLICATION_JSON)).andExpect(status().isForbidden()); mvc.perform(post("/api/payments/reconciliation/run").header("Authorization","Bearer "+jwt("MERCHANT_STAFF")).content("{}").contentType(MediaType.APPLICATION_JSON)).andExpect(status().isForbidden()); mvc.perform(post("/api/payments/reconciliation/run").header("Authorization","Bearer "+jwt("ADMIN")).content("{}").contentType(MediaType.APPLICATION_JSON)).andExpect(status().isOk()); mvc.perform(get("/api/payments/reconciliation/items").header("Authorization","Bearer "+jwt("ADMIN"))).andExpect(status().isOk()); mvc.perform(get("/api/payments/reconciliation/items/unknown").header("Authorization","Bearer "+jwt("ADMIN"))).andExpect(status().isNotFound()); }
 @Test void expiredPendingAndMismatchBecomeVisibleWithoutParkingCalls() throws Exception { var expired=order("expired",PaymentStatus.PENDING,Instant.now().minusSeconds(60)); var mismatch=order("mismatch",PaymentStatus.MISMATCHED,Instant.now().plusSeconds(600)); orders.save(expired);orders.save(mismatch); mvc.perform(post("/api/payments/reconciliation/run").header("Authorization","Bearer "+jwt("ADMIN")).content("{}").contentType(MediaType.APPLICATION_JSON)).andExpect(status().isOk()).andExpect(jsonPath("$.summary.expiredPendingOrders").value(org.hamcrest.Matchers.greaterThanOrEqualTo(1))).andExpect(jsonPath("$.summary.mismatchedOrders").value(org.hamcrest.Matchers.greaterThanOrEqualTo(1))); Assertions.assertEquals(PaymentStatus.EXPIRED,orders.findById("expired").orElseThrow().status()); }
 private PaymentOrder order(String id,PaymentStatus s,Instant expires){return new PaymentOrder(id,"CODE-"+id,PaymentTargetType.PARKING_SESSION,"session-"+id,5000,"VND",s,Instant.now().minusSeconds(3600),expires,s==PaymentStatus.PAID?Instant.now():null,true,null);} private String jwt(String role){Instant n=Instant.now();return Jwts.builder().subject("test").claim("roles",List.of(role)).issuedAt(Date.from(n)).expiration(Date.from(n.plusSeconds(3600))).signWith(Keys.hmacShaKeyFor(SECRET.getBytes(StandardCharsets.UTF_8))).compact();}}
